import React , {useState} from "react";


function App() {
    const products = [
    {
      id: 1,
      name: "Laptop",
      category: "Electronics",
      price: 50000,
    },
    {
      id: 2,
      name: "T-Shirt",
      category: "Clothing",
      price: 1200,
    },
    {
      id: 3,
      name: "Mobile",
      category: "Electronics",
      price: 30000,
    },
    {
      id: 4,
      name: "Jeans",
      category: "Clothing",
      price: 2000,
    },
  ];


  const [electronics, setElectronics] = useState(false);
  const [clothing, setClothings] = useState(false);

 const filteredProducts = products.filter((product) => {

  if (!electronics && !clothing) {
    return true;
  }

  if (electronics && product.category === "Electronics") {
    return true;
  }

  if (clothing && product.category === "Clothing") {
    return true;
  }

  return false;
});

  return (
    <div>
      <h1>Product Category Filter</h1>

      <label><input type="checkbox" checked= {electronics} onChange={()=>setElectronics(!electronics)}/>Electronics</label>
      <br/>
      <label><input type="checkbox" checked= {clothing} onChange={()=>setClothings(!clothing)}/>Clothing</label>
      <br/>

      <table border={1} cellPadding={10}>
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Category</th>
            <th>Price</th>
          </tr>
        </thead>
        <tbody>
          {filteredProducts.map((product)=>(
            <tr key={product.id}>
              <td>{product.id}</td>
              <td>{product.name}</td>
              <td>{product.category}</td>
              <td>{product.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

export default App